// Parse the manifest JSON and return one item per clip
const raw = $input.first().json.stdout || '';
let manifest;
try {
  manifest = JSON.parse(raw);
} catch (e) {
  throw new Error('Failed to parse manifest JSON: ' + raw.substring(0, 200));
}

const clips = manifest.clips || [];
if (clips.length === 0) {
  throw new Error('No clips found in manifest');
}

return clips.map(clip => ({
  json: {
    title: clip.title,
    score: clip.score,
    reason: clip.reason,
    start_time: clip.start_time,
    end_time: clip.end_time,
    output_file: clip.output_file,
    source: manifest.source,
    run_at: manifest.run_at
  }
}));

// Runs ONCE for all items — builds a single summary message for OpenClaw
const uploadedItems = $input.all();
const clipMeta = $('Code: Parse Clips').all();

const lines = uploadedItems.map((item, i) => {
  const meta = clipMeta[i]?.json || {};
  const fileId = item.json?.id || '';
  const link = fileId
    ? `https://drive.google.com/file/d/${fileId}/view`
    : '(link unavailable)';
  const duration = meta.end_time && meta.start_time
    ? Math.round(meta.end_time - meta.start_time) + 's'
    : '?';
  return `${i + 1}. [${meta.score || '?'}/10] ${meta.title || 'Clip ' + (i + 1)} (${duration}) - ${link}`;
});

const source = clipMeta[0]?.json?.source || 'unknown source';
const message = `Video Clips Ready! Source: ${source} | ${lines.join(' | ')}`;

return [{ json: { message } }];
